-- Class Weapon proficiencies

-- Cleric (2)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 2, weapon_proficiency.id FROM weapon_proficiency
WHERE weapon_proficiency.name IN ('club', 'Footman\'s Flail', 'Horseman\'s Flail', 'hammer', 'Footman\'s mace', 'Horseman\'s mace', 'staff', 'lasso', 'sap', 'staff sling');

-- Druid (3)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 3, weapon_proficiency.id FROM weapon_proficiency
WHERE weapon_proficiency.name IN ('aklys', 'club', 'dagger', 'dart', 'garrot', 'hammer', 'lasso', 'sap', 'sling', 'scimitar', 'spear', 'staff', 'staff sling', 'khopesh sword' , 'whip');

-- Fighter (4)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 4, weapon_proficiency.id FROM weapon_proficiency;

-- Paladin (5)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 5, weapon_proficiency.id FROM weapon_proficiency;

-- Ranger (6)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 6, weapon_proficiency.id FROM weapon_proficiency;

-- Magic-User (7)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 7, weapon_proficiency.id FROM weapon_proficiency
WHERE weapon_proficiency.name IN ('caltrop', 'dagger', 'dart', 'knife', 'sling', 'staff');

-- Illusionist (8)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 8, weapon_proficiency.id FROM weapon_proficiency
WHERE weapon_proficiency.name IN ('caltrop', 'dagger', 'dart', 'knife', 'sling', 'staff');

-- Thief (9)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 9, weapon_proficiency.id FROM weapon_proficiency
WHERE weapon_proficiency.name IN ('short bow', 'caltrop', 'club', 'hand crossbow', 'dagger', 'dart', 'garrot', 'knife', 'sap', 'sling', 'broad sword', 'falchion sword',  'long sword', 'short sword');

-- Assassin (10)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 10, weapon_proficiency.id FROM weapon_proficiency;

-- Monk (11)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 11, weapon_proficiency.id FROM weapon_proficiency
WHERE weapon_proficiency.name IN ('bo stick', 'club', 'light crossbow', 'heavy crossbow', 'great crossbow', 'dagger', 'hand axe', 'javelin', 'jo stick', 'spear', 'staff');

-- Monk (Polearm)
INSERT INTO character_class_weapon_proficiency (character_class_id, weapon_proficiency_id)
SELECT 11, weapon_proficiency.id FROM weapon_proficiency
JOIN weapon_catalog ON weapon_catalog.weapon_proficiency_id = weapon_proficiency.id
WHERE weapon_catalog.subtype = 8;

